  ('disabled-e0adf6cd-moex-00188', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '新北市政府與臺北市政府締結行政契約，依行政程序法規定，下列敘述何 者正確？', '["當事人之一方得就相對人契約之履行，依書面約定之方式，為必要之 指導", "締約機關所屬公法人之其他機關於契約關係外行使公權力，致相對人履 行契約義務而顯增費用，相對人得向締約機關請求損失補償", "當事人之一方為防止對公益之重大危害，得於必要範圍內終止契約", "因有情事重大變更，非當時所得預料，而依原約定顯失公平者，當事人 之一方得請求他方適當調整契約內容"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
