  ('disabled-e0adf6cd-moex-00192', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於公法上之請求權除法律另有規定外，依行政程序法規定，下列敘述何 者錯誤？', '["行政機關為請求權人時，時效為5年", "人民為請求權人時，時效為10年", "請求權時效自請求權人知悉事由時起算", "時效之完成採取消滅主義"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00193', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何者非提起訴願之先行程序？', '["稅捐義務人對於課稅處分不服提起之復查", "大學生對於退學處分不服提起之申訴", "藥商對於罰鍰處分不服，依藥事法申請之復核", "公務員不服免職處分，向公務人員保障暨培訓委員會提起之復審"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00194', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何種情況，訴願機關應以決定駁回？', '["原處分機關事實認定有誤", "訴願書不合法定程式", "行政處分已不存在", "對非行政處分提起訴願"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00195', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '居住於臺中市之甲其所有位於高雄市之土地被交通部徵收，以建設快速道 路，就此徵收處分發生爭訟時，應由下列何法院管轄？', '["臺中高等行政法院", "臺北高等行政法院", "高雄高等行政法院", "甲得指定臺北或高雄高等行政法院為管轄法院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00196', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '甲以鄰居乙之建築工程違法而請求丙主管機關撤銷乙之建築許可，遭丙駁 回後提起訴願，經丁訴願機關作成訴願決定撤銷原處分，乙對此訴願決定 不服時，下列敘述何者正確？', '["以丙為被告提起撤銷之訴", "以丙為被告提起確認之訴", "以丁為被告提起撤銷之訴", "以丁為被告提起確認之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00197', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-111-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '有關國家賠償制度，下列敘述何者錯誤？', '["人民得因國家機關違法行使公權力，受到損害，請求國家賠償", "人民因私人擁有所有權之公共設施受害者，仍得依法請求國家賠償", "人民不得透過行政訴訟程序，請求國家機關賠償因違法行使公權力所致 之損害", "國家賠償之訴，國家賠償法及其施行細則未規定者，適用民事訴訟法相 關規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "e417dd4ca5ed", "answer_pdf_sha1": "a2eaaa36477e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "303", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL)
